+asx_status asx_happy_eyeballs_order(asx_resolve_result *out, const asx_resolve_result *in,
+                                    asx_addr_family preferred_family) {
+    uint32_t pass;
+    uint32_t i;
+
+    if (out == NULL || in == NULL) return ASX_E_INVALID_ARGUMENT;
+    memset(out, 0, sizeof(*out));
+
