+            if (in->addrs[i].family == want && out->count < ASX_RESOLVE_MAX_RESULTS) {
+                out->addrs[out->count++] = in->addrs[i];
+            }
+        }
+    }
+    return out->count == 0u ? ASX_E_NOT_FOUND : ASX_OK;
